/**
 * Tests for Analytics API Service
 */

import { apiFetch } from "../../services/api";
import {
  getProjectAnalytics,
  getReportTemplates,
  generateReport,
  exportData,
  getDashboardMetrics,
  getTimeSeriesData,
} from "../../services/analyticsApi";

// Mock API
jest.mock("../../services/api", () => ({
  apiFetch: jest.fn(),
}));

describe("analyticsApi", () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe("getProjectAnalytics", () => {
    it("should fetch project analytics", async () => {
      const mockAnalytics = {
        projectId: "proj-1",
        projectName: "Test Project",
        overview: {
          progress: 75,
          budgetUtilization: 80,
          timelineStatus: "on-track",
          tasksCompleted: 15,
          tasksTotal: 20,
          teamSize: 10,
        },
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockAnalytics);

      const result = await getProjectAnalytics("proj-1");

      expect(apiFetch).toHaveBeenCalledWith("/analytics/projects/proj-1", {
        method: "GET",
      });
      expect(result.projectId).toBe("proj-1");
      expect(result.overview.progress).toBe(75);
    });

    it("should include date range parameters", async () => {
      (apiFetch as jest.Mock).mockResolvedValue({});

      await getProjectAnalytics("proj-1", {
        startDate: "2026-01-01",
        endDate: "2026-01-31",
      });

      expect(apiFetch).toHaveBeenCalledWith(
        expect.stringContaining("startDate=2026-01-01"),
        expect.any(Object),
      );
    });
  });

  describe("getReportTemplates", () => {
    it("should fetch available report templates", async () => {
      const mockTemplates = [
        {
          id: "template-1",
          name: "Project Summary",
          type: "project",
          format: "pdf",
        },
        {
          id: "template-2",
          name: "Financial Report",
          type: "financial",
          format: "excel",
        },
      ];

      (apiFetch as jest.Mock).mockResolvedValue(mockTemplates);

      const result = await getReportTemplates();

      expect(apiFetch).toHaveBeenCalledWith("/analytics/templates", {
        method: "GET",
      });
      expect(result).toHaveLength(2);
    });

    it("should filter by report type", async () => {
      (apiFetch as jest.Mock).mockResolvedValue([]);

      await getReportTemplates("financial");

      expect(apiFetch).toHaveBeenCalledWith(
        expect.stringContaining("type=financial"),
        expect.any(Object),
      );
    });
  });

  describe("generateReport", () => {
    it("should generate a report", async () => {
      const mockResponse = {
        reportId: "report-123",
        status: "generating",
        downloadUrl: null,
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockResponse);

      const result = await generateReport({
        templateId: "template-1",
        projectId: "proj-1",
        format: "pdf",
      });

      expect(apiFetch).toHaveBeenCalledWith("/analytics/reports/generate", {
        method: "POST",
        body: expect.objectContaining({
          templateId: "template-1",
          projectId: "proj-1",
        }),
      });
      expect(result.reportId).toBe("report-123");
    });
  });

  describe("exportData", () => {
    it("should export data in specified format", async () => {
      const mockResponse = {
        downloadUrl: "https://example.com/export.csv",
        expiresAt: "2026-01-24T00:00:00Z",
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockResponse);

      const result = await exportData({
        reportType: "tasks",
        format: "csv",
        filters: { projectId: "proj-1" },
      });

      expect(apiFetch).toHaveBeenCalledWith("/analytics/export", {
        method: "POST",
        body: expect.objectContaining({
          format: "csv",
        }),
      });
      expect(result.downloadUrl).toContain("export.csv");
    });
  });

  describe("getDashboardMetrics", () => {
    it("should fetch dashboard metrics", async () => {
      const mockMetrics = {
        totalProjects: 10,
        activeProjects: 5,
        completedProjects: 4,
        overallProgress: 65,
        totalBudget: 1000000,
        budgetSpent: 650000,
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockMetrics);

      const result = await getDashboardMetrics();

      expect(apiFetch).toHaveBeenCalledWith("/analytics/dashboard", {
        method: "GET",
      });
      expect(result.totalProjects).toBe(10);
      expect(result.overallProgress).toBe(65);
    });
  });

  describe("getTimeSeriesData", () => {
    it("should fetch time series data", async () => {
      const mockData = {
        labels: ["Jan", "Feb", "Mar"],
        datasets: [
          {
            label: "Progress",
            data: [30, 50, 75],
          },
        ],
      };

      (apiFetch as jest.Mock).mockResolvedValue(mockData);

      const result = await getTimeSeriesData({
        metric: "progress",
        period: "monthly",
        projectId: "proj-1",
      });

      expect(apiFetch).toHaveBeenCalledWith(
        expect.stringContaining("/analytics/timeseries"),
        expect.any(Object),
      );
      expect(result.labels).toHaveLength(3);
    });
  });
});
